/* ═══════════════════════════════════════════════════════════════════════════
   PYTHON BACKEND CONFIGURATION
   Tries to fetch live data from the Python engine on mount.
   If unavailable (Claude artifact mode), falls back to baked-in data below.
   Start backend: uvicorn main:app --port 8000
   ═══════════════════════════════════════════════════════════════════════════ */
const ENGINE_API = (typeof import.meta !== "undefined" && import.meta.env?.VITE_ENGINE_API)
  || "http://localhost:8000";
const DEBOUNCE_MS = 300;

const _store = {
  async get(k){try{if(typeof window!=="undefined"&&window.storage?.get)return await _store.get(k);const v=localStorage.getItem(k);return v?{value:v}:null}catch(e){return null}},
  async set(k,v){try{if(typeof window!=="undefined"&&window.storage?.set)return await _store.set(k,v);localStorage.setItem(k,v);return{key:k,value:v}}catch(e){return null}},
  async delete(k){try{if(typeof window!=="undefined"&&window.storage?.delete)return await _store.delete(k);localStorage.removeItem(k);return{key:k,deleted:true}}catch(e){return null}}
};

// Decode raw monthly array-of-arrays from Python engine into chart objects.
// Same field names as the fallback M decoder below.
function decodeMonthlyRaw(rawRows) {
  return rawRows.map(r => ({
    yr:r[0], mo:r[1], gross:r[2], tax:r[3], take:r[4], spend:r[5], left:r[6],
    sn:r[7], sav:r[8], unalloc:r[9], short:r[10],
    k401:r[11], tsp:r[12], roth:r[13], c529:r[14], pri:r[15], acorn:r[16], brok:r[17],
    slU:r[18], slS:r[19], cab:r[20], mort:r[21], carLn:r[22],
    debt:r[23], nw:r[24], home:r[25], events:r[26],
    label: `${r[0]}-${String(r[1]).padStart(2,'0')}`,
    cash: r[7] + r[8] + r[9],
    inv: r[11] + r[12] + r[13] + r[14] + r[15] + r[16] + r[17],
    equity: Math.max(0, r[25] - r[21]),
  }));
}

// Maps What-If editor keys -> Python engine parameter names
const FIELD_TO_ENGINE = {
  hourlyRate:"hourly_rate", hoursPerWeek:"hours_week", weeksPerYear:"weeks_year",
  otHours:"ot_hours", raise:"annual_raise", jumpYear:"jump_year",
  jumpSalary:"jump_salary",
  wifeStart:"wife_year1_salary", wifeRaise:"wife_raise",
  wifeJumpYear:"wife_jump_year", wifeJumpSalary:"wife_jump_salary",
  partTimePct:"part_time_pct",
  retireAge:"retire_age", ssMonthly:"ss_monthly", wifeSS:"wife_ss",
  pensionMonthly:"pension_monthly", pensionStartAge:"pension_start_age",
  stopDrillAge:"stop_drill_age",
  housePrice:"house_price", downPct:"down_pct", mortRate:"mort_rate",
  mortYears:"mort_years", rent:"rent", buyYear:"buy_year_of_work",
  appreciation:"home_appreciation",
  invReturn:"inv_return", k401pct:"k401_pct", matchPct:"k401_match",
  tspMonthly:"tsp_monthly", rothMonthly:"roth_monthly",
  brokerageReturn:"brok_return", divYield:"div_yield",
  numKids:"num_kids", kid1Year:"kid1_year", kid2Year:"kid2_year",
  kid3Year:"kid3_year", kid4Year:"kid4_year",
  slUnsubBal:"unsub_bal", slSubBal:"sub_bal", cabelasBal:"cab_bal",
  groceries:"groceries", dining:"dining", funMoney:"fun_money",
  misc:"misc", phone:"phone",
  inflation:"inflation", healthcareInflation:"healthcare_inflation",
  // Rental property
  rentalEnabled:"rental_enabled", rentalPurchaseYear:"rental_purchase_year",
  rentalPrice:"rental_price", rentalDownPct:"rental_down_pct",
  rentalMortRate:"rental_mort_rate", rentalMortYears:"rental_mort_years",
  rentalMonthlyRent:"rental_monthly_rent", rentalRentIncrease:"rental_rent_increase",
  rentalVacancy:"rental_vacancy", rentalMgmtFee:"rental_mgmt_fee",
  // Withdrawal strategy
  withdrawalRate:"withdrawal_rate",
  rothConversionStrategy:"roth_conversion_strategy",
  rothConversionAmount:"roth_conversion_amount",
  rothTargetBracket:"roth_target_bracket",
};

// Convert editor inputs to engine params (only changed fields)
function toEngineParams(editorInputs, defaults) {
  const params = {};
  for (const [k, val] of Object.entries(editorInputs)) {
    const ek = FIELD_TO_ENGINE[k];
    if (ek && val !== defaults[k]) params[ek] = val;
  }
  return params;
}


