// Format a value for display based on format type
const fmtInput = (v, f) => {
  if (f === "text") return String(v || "");
  if (f === "$") return `$${Math.round(v).toLocaleString()}`;
  if (f === "$K") return v >= 1000 ? `$${(v/1000).toFixed(0)}K` : `$${Math.round(v)}`;
  if (f === "$/hr") return `$${v.toFixed(2)}/hr`;
  if (f === "%") return `${(v*100).toFixed(1)}%`;
  if (f === "%2") return `${(v*100).toFixed(2)}%`;
  if (f === "int") return String(Math.round(v));
  if (f === "yr") return `Year ${v}`;
  if (f === "mo") return `${v} months`;
  return String(v);
};

